    if (Primitives.isPrimitiveOrWrapper(type)) {
        return Primitives.defaultValueForPrimitiveOrWrapper(type);
    } else if (Collection.class.isAssignableFrom(type)) {
        return createCollectionInstance(type);
    } else if (Map.class.isAssignableFrom(type)) {
        return createMapInstance(type);
    }
    return null;
}

private Collection<Object> createCollectionInstance(Class<?> type) {
    if (type == List.class || type == LinkedList.class) {
        return new LinkedList<Object>();
    } else if (type == Set.class || type == HashSet.class) {
        return new HashSet<Object>();
    } else if (type == SortedSet.class || type == TreeSet.class) {
        return new TreeSet<Object>();
    } else if (type == LinkedHashSet.class) {
        return new LinkedHashSet<Object>();
    }
    return new ArrayList<Object>(); // Default collection type
}

private Map<Object, Object> createMapInstance(Class<?> type) {
    if (type == Map.class || type == HashMap.class) {
        return new HashMap<Object, Object>();
    } else if (type == SortedMap.class || type == TreeMap.class) {
        return new TreeMap<Object, Object>();
    } else if (type == LinkedHashMap.class) {
        return new LinkedHashMap<Object, Object>();
    }
    return new HashMap<Object, Object>(); // Default map type
}

